-- =====================================================================
-- Mount Hyjal (map 750)  --  32  Molten Front PHASED storyline -> base-visible
-- ---------------------------------------------------------------------
-- Phase 3 of the Neltharion downport. Project Neltharion gates the Molten Front /
-- Firelands daily storyline behind phaseMask (excluded from base layer 30, which is
-- phaseMask&1). We have no phase-progression backend on 3.3.5, so we pull the COHERENT
-- FINAL hub -- nelt phaseMask 64, area 5781 "The Molten Front": the Hyjal assault forces
-- (Malfurion Stormrage, Arch Druid Hamuul Runetotem, Skylord Omnuron, Captain Saynna
-- Stormrunner, Hyjal Ritualist, Hyjal Assault Trooper) -- and re-emit it at phaseMask 1.
--
-- We deliberately do NOT stack the Hyjal-proper construction phases 16/32 (Sethria's Roost
-- battlefield, ~400 hostile mobs each): they are a separate, conflicting storyline progression.
--
-- DISTINCT guid block from layer 30: creature +14000000, gameobject +14500000, waypoint +132000000, pool +132000000.
-- Templates re-use the dc clone (id = nelt_id + 3600000), already imported by 29/01. Idempotent.
-- Apply AFTER 29 and 30.
-- =====================================================================

-- Idempotent: drop the prior Phase-3 block.
DELETE FROM `creature`        WHERE `guid` BETWEEN 14000000 AND 14499999;
DELETE FROM `creature_addon`  WHERE `guid` BETWEEN 14000000 AND 14499999;
DELETE FROM `gameobject`      WHERE `guid` BETWEEN 14500000 AND 14999999;
DELETE FROM `pool_creature`   WHERE `pool_entry` BETWEEN 132000000 AND 132999999;
DELETE FROM `pool_gameobject` WHERE `pool_entry` BETWEEN 132000000 AND 132999999;
DELETE FROM `pool_template`   WHERE `entry` BETWEEN 132000000 AND 132999999;
DELETE FROM `waypoint_data`   WHERE `id` BETWEEN 132000000 AND 132999999;


-- Orphan cleanup: drop Phase-3 spawns whose +3600000 clone template was not imported
-- (the Wondi's-Bunny trigger targets 75000/75160 -- cosmetic, harmless to drop), + dangling addon/pool.
DELETE c FROM `creature` c LEFT JOIN `creature_template` ct ON ct.`entry`=c.`id` WHERE c.`map`=750 AND c.`guid` BETWEEN 14000000 AND 14499999 AND ct.`entry` IS NULL;
DELETE g FROM `gameobject` g LEFT JOIN `gameobject_template` gt ON gt.`entry`=g.`id` WHERE g.`map`=750 AND g.`guid` BETWEEN 14500000 AND 14999999 AND gt.`entry` IS NULL;
DELETE a FROM `creature_addon` a LEFT JOIN `creature` c ON c.`guid`=a.`guid` WHERE a.`guid` BETWEEN 14000000 AND 14499999 AND c.`guid` IS NULL;
DELETE p FROM `pool_creature` p LEFT JOIN `creature` c ON c.`guid`=p.`guid` WHERE p.`pool_entry` BETWEEN 132000000 AND 132999999 AND c.`guid` IS NULL;
DELETE p FROM `pool_gameobject` p LEFT JOIN `gameobject` g ON g.`guid`=p.`guid` WHERE p.`pool_entry` BETWEEN 132000000 AND 132999999 AND g.`guid` IS NULL;
